let smoother;
function smoothScroll() {
  if (!isMobile() && window.innerWidth > 768) {
    smoother = ScrollSmoother.create({
      wrapper: "#smooth-wrapper",
      content: ".content",
      smooth: 1.2,
      // how long (in seconds) it takes to "catch up" to the native scroll position
      //smoothTouch: .1
      effects: true,
      // looks for data-speed and data-lag attributes on elements
      normalizeScroll: true // prevents address bar from showing/hiding on most devices, solves various other browser inconsistencies
      //ease: "elastic"
      //ignoreMobileResize: true // skips ScrollTrigger.refresh() on mobile resizes from address bar showing/hiding
    });
    smoother.effects(".parallax-wrap img", {
      speed: "auto"
    });
    let pImg = document.querySelectorAll(".parallax-img");
    pImg.forEach(pi => {
      let thisImg = pi.querySelector("img");
      let thisHeight = thisImg.offsetHeight + "px";
      pi.style.height = thisHeight;
    });
    smoother.effects(".parallax-img img", {
      speed: ".75"
    });
    const scrollTo = gsap.utils.toArray(".scroll-to");
    scrollTo.forEach(st => {
      const scrollTarget = st.dataset.scroll;
      // console.log(scrollTarget)
      st.addEventListener("click", function () {
        smoother.scrollTo("#" + scrollTarget, true, "top 0%");
      });
    });
    return smoother;
  }
}
